package com.example.logging

import android.app.Application
import timber.log.Timber

class LoggingApplication : Application() {
    override fun onCreate() {
        super.onCreate()
        // Plant a tree for logging. You can customize this tree as needed.
        if (BuildConfig.DEBUG) {
            Timber.plant(Timber.DebugTree())
        } else {
            Timber.plant(ProductionTree())
        }
    }
}

class ProductionTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        // In production, log everything as verbose. You might also forward these logs to a remote server.
        // Here you can integrate with crash reporting tools or remote logging systems.
        // For demonstration, we're simply printing them.
        android.util.Log.println(android.util.Log.VERBOSE, tag, message)
        t?.let {
            android.util.Log.println(android.util.Log.ERROR, tag, android.util.Log.getStackTraceString(it))
        }
    }
}

object LoggingSystem {

    fun logUserAuthentication(isSuccessful: Boolean, userId: String, additionalInfo: String? = null) {
        val status = if (isSuccessful) "SUCCESS" else "FAILURE"
        val info = additionalInfo ?: "No additional info"
        Timber.v("User Authentication Attempt: Status = $status, UserID = $userId, Info = $info")
    }

    fun logDatabaseQuery(query: String, parameters: Map<String, Any?>? = null) {
        val params = parameters?.entries?.joinToString { "${it.key}=${it.value}" } ?: "No parameters"
        Timber.v("Database Query: \"$query\" with parameters: $params")
    }

    fun logApiRequest(method: String, url: String, headers: Map<String, String?>? = null, body: String? = null) {
        val headerString = headers?.entries?.joinToString(separator = ", ") { "${it.key}=${it.value}" } ?: "No headers"
        val bodyString = body ?: "No body"
        Timber.v("API Request: Method = $method, URL = $url, Headers = [$headerString], Body = $bodyString")
    }

    fun logException(throwable: Throwable) {
        Timber.e(throwable, "Exception occurred")
    }
}

